// todosSlice.js
import { createSlice } from '@reduxjs/toolkit';

const initialState = [];

const todosSlice = createSlice({
  name: 'todos',
  initialState,
  reducers: {
    addTodo: (state, action) => {
      // action.payload sẽ là nội dung của công việc mới
      state.push({ id: new Date().toISOString(), text: action.payload, completed: false });
    }
  }
});

export const { addTodo } = todosSlice.actions;
export default todosSlice.reducer;

